node_a = input_node('a')
node_b = input_node('b')

name_a = ''
name_b = ''

if node_a:
    if 'unet_name' in node_a.inputs:
        name_a = str(node_a.inputs['unet_name'])

if node_b:
    if 'unet_name' in node_b.inputs:
        name_b = str(node_b.inputs['unet_name'])

name_a_clean = name_a.replace('\\', '/')

if '.safetensors' in name_a_clean:
    name_a_clean = name_a_clean.replace('.safetensors', '')

if '/' in name_a_clean:
    name_a_clean = name_a_clean.split('/')[-1]

return name_a_clean + ', ' + name_b

pll_a = input_node('a')
pll_b = input_node('b')

parts = []

if pll_a:
    for key in pll_a.inputs:
        v = pll_a.inputs[key]
        if 'lora' in v:
            if v['on']:
                if v['lora']:
                    name = v['lora']
                    name = name.replace('\\', '/')
                    name = name.replace('.safetensors', '')
                    name = name.split('/')[-1]

                    strength = 1
                    if 'strength' in v:
                        strength = v['strength']

                    parts.append(f'<lora:{name}:{strength}>')

if pll_b:
    for key in pll_b.inputs:
        v = pll_b.inputs[key]
        if 'lora' in v:
            if v['on']:
                if v['lora']:
                    name = v['lora']
                    name = name.replace('\\', '/')
                    name = name.replace('.safetensors', '')
                    name = name.split('/')[-1]

                    strength = 1
                    if 'strength' in v:
                        strength = v['strength']

                    parts.append(f'<lora:{name}:{strength}>')

return ', '.join(parts)
